<template>
  <div class="register-container">
    <el-card class="register-card">
      <template #header>
        <div class="card-header">
          <h2>注册 A2A工作流平台</h2>
        </div>
      </template>
      
      <el-alert
        v-if="error"
        :title="error"
        type="error"
        :closable="false"
        show-icon
        class="register-alert"
      />
      
      <el-form 
        ref="registerForm" 
        :model="formData" 
        :rules="rules" 
        label-position="top"
        @submit.native.prevent="handleRegister"
      >
        <input type="hidden" name="csrfmiddlewaretoken" :value="csrfToken">
        
        <el-form-item label="用户名" prop="username">
          <el-input 
            v-model="formData.username" 
            name="username"
            placeholder="请输入用户名"
          />
        </el-form-item>
        
        <el-form-item label="电子邮箱" prop="email">
          <el-input 
            v-model="formData.email" 
            name="email"
            placeholder="请输入电子邮箱"
            type="email"
          />
        </el-form-item>
        
        <el-form-item label="密码" prop="password1">
          <el-input 
            v-model="formData.password1" 
            name="password1"
            type="password" 
            placeholder="请输入密码"
            show-password
          />
        </el-form-item>
        
        <el-form-item label="确认密码" prop="password2">
          <el-input 
            v-model="formData.password2" 
            name="password2"
            type="password" 
            placeholder="请再次输入密码"
            show-password
          />
        </el-form-item>
        
        <div class="form-actions">
          <el-button 
            type="primary" 
            @click="handleRegister"
            :loading="isLoading" 
            class="register-button"
          >
            注册
          </el-button>
        </div>
        
        <div class="register-footer">
          <p>已有账号？<router-link to="/login">立即登录</router-link></p>
        </div>
      </el-form>
    </el-card>
  </div>
</template>

<script>
import { ref, reactive, computed, onMounted } from 'vue'
import { useRouter } from 'vue-router'
import { useAuthStore } from '@/store/auth'
import { ElMessage } from 'element-plus'
import axios from 'axios'

export default {
  name: 'RegisterView',
  setup() {
    const router = useRouter()
    const authStore = useAuthStore()
    const registerForm = ref(null)
    const csrfToken = ref('')
    
    // 表单数据
    const formData = reactive({
      username: '',
      email: '',
      password1: '',
      password2: ''
    })
    
    // 验证两次密码是否一致
    const validatePassConfirm = (rule, value, callback) => {
      if (value !== formData.password1) {
        callback(new Error('两次输入的密码不一致'))
      } else {
        callback()
      }
    }
    
    // 表单校验规则
    const rules = {
      username: [
        { required: true, message: '请输入用户名', trigger: 'blur' },
        { min: 3, max: 30, message: '用户名长度应在3-30个字符之间', trigger: 'blur' }
      ],
      email: [
        { required: true, message: '请输入电子邮箱', trigger: 'blur' },
        { type: 'email', message: '请输入正确的电子邮箱格式', trigger: 'blur' }
      ],
      password1: [
        { required: true, message: '请输入密码', trigger: 'blur' },
        { min: 6, message: '密码长度不能小于6个字符', trigger: 'blur' }
      ],
      password2: [
        { required: true, message: '请再次输入密码', trigger: 'blur' },
        { validator: validatePassConfirm, trigger: 'blur' }
      ]
    }
    
    // 计算属性
    const isLoading = computed(() => authStore.isLoading)
    const error = computed(() => authStore.error)
    
    // 获取CSRF Token
    const getCsrfToken = () => {
      const token = document.cookie
        .split('; ')
        .find(row => row.startsWith('csrftoken='))
        ?.split('=')[1]
      
      if (token) {
        csrfToken.value = token
      } else {
        // 如果cookie中没有csrftoken，从服务器获取
        axios.get('/csrf/')
          .then(() => {
            const newToken = document.cookie
              .split('; ')
              .find(row => row.startsWith('csrftoken='))
              ?.split('=')[1]
            
            if (newToken) {
              csrfToken.value = newToken
            }
          })
          .catch(err => {
            console.error('获取CSRF令牌失败', err)
          })
      }
    }
    
    // 处理注册
    const handleRegister = async () => {
      if (!registerForm.value) return
      
      try {
        await registerForm.value.validate()
        
        const success = await authStore.register({
          username: formData.username,
          email: formData.email,
          password1: formData.password1,
          password2: formData.password2
        })
        
        if (success) {
          ElMessage.success('注册成功')
          router.push('/')
        }
      } catch (error) {
        console.error('注册失败', error)
      }
    }
    
    // 生命周期钩子
    onMounted(() => {
      // 获取CSRF令牌
      getCsrfToken()
      
      // 如果已登录，直接跳转到首页
      if (authStore.isAuthenticated) {
        router.push('/')
      }
    })
    
    return {
      registerForm,
      formData,
      rules,
      isLoading,
      error,
      handleRegister,
      csrfToken
    }
  }
}
</script>

<style scoped>
.register-container {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 40px 20px;
  min-height: calc(100vh - 240px);
}

.register-card {
  width: 100%;
  max-width: 420px;
}

.card-header {
  text-align: center;
}

.register-alert {
  margin-bottom: 20px;
}

.form-actions {
  margin-top: 24px;
}

.register-button {
  width: 100%;
}

.register-footer {
  margin-top: 20px;
  text-align: center;
}

.register-footer a {
  color: var(--el-color-primary);
  text-decoration: none;
}
</style> 